  'AI-enhanced photo, video editing; local, secure processing.',
  'https://cdn2.futurepedia.io/d89e4c4b1e3f2ba002b18b3d796f655793cb7f67-128x128.png?w=256',
  'https://cdn2.futurepedia.io/2026-04-27T18-05-35.105Z-kf2XIWzVa7NXVNDIDa9tET9aymRq76kFe.webp?w=3840',
  0,
  1,
  0,
  NULL,
